"use client";

import { Tabs as TabsRoot, type TabsProps } from "./tabs";
import { TabsList, type TabsListProps } from "./tabs-list";
import { TabsTrigger, type TabsTriggerProps, tabsTriggerVariants } from "./tabs-trigger";
import { TabsContent, type TabsContentProps } from "./tabs-content";
import { useTabsContext, type TabsContextValue } from "./tabs-context";

const Tabs = Object.assign(TabsRoot, {
  List: TabsList,
  Trigger: TabsTrigger,
  Content: TabsContent,
});

export { Tabs, type TabsProps };
export { TabsList, type TabsListProps };
export { TabsTrigger, tabsTriggerVariants, type TabsTriggerProps };
export { TabsContent, type TabsContentProps };
export { useTabsContext, type TabsContextValue };

"use client";

import {
  Children,
  isValidElement,
  type HTMLAttributes,
  type ReactNode,
  type Ref,
  useId,
  useMemo,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { cn } from "@/lib/utils";
import { TabsContext } from "./tabs-context";
import { TabsContent } from "./tabs-content";
import { TabsTrigger } from "./tabs-trigger";

export interface TabsProps extends Omit<HTMLAttributes<HTMLDivElement>, "defaultValue" | "onChange"> {
  value?: string;
  onChange?: (value: string) => void;
  defaultValue?: string;
  orientation?: "horizontal" | "vertical";
  variant?: "default" | "underline";
  activationMode?: "automatic" | "manual";
  ref?: Ref<HTMLDivElement>;
}

interface TabTriggerElementProps {
  value?: string;
  disabled?: boolean;
  children?: ReactNode;
}

interface TabMetadata {
  enabledValues: string[];
  panelValues: string[];
  triggerValues: string[];
}

function collectTabMetadata(children: ReactNode): TabMetadata {
  const metadata: TabMetadata = {
    enabledValues: [],
    panelValues: [],
    triggerValues: [],
  };

  Children.forEach(children, (child) => {
    if (!isValidElement<TabTriggerElementProps>(child)) return;
    if (child.type === TabsRoot) return;

    if (child.type === TabsTrigger && typeof child.props.value === "string") {
      metadata.triggerValues.push(child.props.value);
      if (!child.props.disabled) metadata.enabledValues.push(child.props.value);
      return;
    }

    if (child.type === TabsContent && typeof child.props.value === "string") {
      metadata.panelValues.push(child.props.value);
    }

    const childMetadata = collectTabMetadata(child.props.children);
    metadata.enabledValues.push(...childMetadata.enabledValues);
    metadata.panelValues.push(...childMetadata.panelValues);
    metadata.triggerValues.push(...childMetadata.triggerValues);
  });

  return metadata;
}

function TabsRoot({
  value: controlledValue,
  onChange,
  defaultValue,
  orientation = "horizontal",
  variant = "default",
  activationMode = "automatic",
  children,
  className,
  ref,
  ...rest
}: TabsProps) {
  const tabsId = useId();
  const { enabledValues, panelValues, triggerValues } = useMemo(() => collectTabMetadata(children), [children]);
  const [value, setValue] = useControllableState<string>({
    value: controlledValue,
    defaultValue: defaultValue ?? "",
    onChange,
  });
  const firstEnabledTab = enabledValues[0] ?? "";
  const resolvedValue = enabledValues.includes(value) ? value : firstEnabledTab;

  const contextValue = useMemo(
    () => ({
      tabsId,
      value: resolvedValue,
      onChange: setValue,
      panelValues,
      triggerValues,
      orientation,
      variant,
      activationMode,
    }),
    [tabsId, resolvedValue, setValue, panelValues, triggerValues, orientation, variant, activationMode],
  );

  return (
    <TabsContext value={contextValue}>
      <div
        ref={ref}
        className={cn("flex flex-col", className)}
        data-orientation={orientation}
        {...rest}
      >
        {children}
      </div>
    </TabsContext>
  );
}

export { TabsRoot as Tabs };

"use client";

import { useRef, type HTMLAttributes, type KeyboardEvent, type Ref } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { useNavigation } from "@/hooks/use-navigation";
import { cn } from "@/lib/utils";
import { useTabsContext } from "./tabs-context";

export interface TabsListProps extends HTMLAttributes<HTMLDivElement> {
  loop?: boolean;
  ref?: Ref<HTMLDivElement>;
}

export function TabsList({ children, className, loop = true, onKeyDown, ref, ...rest }: TabsListProps) {
  const { orientation, variant, value, onChange, activationMode } = useTabsContext();

  const containerRef = useRef<HTMLDivElement>(null);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "tab",
    orientation,
    wrap: loop,
    moveFocus: true,
    scopeToContainer: true,
    ...(activationMode === "automatic"
      ? {
          highlighted: value || undefined,
          onHighlightChange: onChange,
        }
      : {
          onEnter: onChange,
          onSelect: onChange,
        }),
  });

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented) navKeyDown(e);
  };

  return (
    <div
      ref={composeRefs(containerRef, ref)}
      className={cn(
        "flex font-mono",
        variant === "underline" ? "border-b border-border gap-8" : "gap-1",
        orientation === "vertical" && "flex-col",
        className
      )}
      role="tablist"
      aria-orientation={orientation}
      onKeyDown={handleKeyDown}
      {...rest}
    >
      {children}
    </div>
  );
}

"use client";

import { type ButtonHTMLAttributes, type MouseEvent, type Ref } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { getTabPanelId, getTabTriggerId, useTabsContext } from "./tabs-context";

export const tabsTriggerVariants = cva(
  "text-sm font-mono transition-colors motion-reduce:transition-none cursor-pointer focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
  {
    variants: {
      variant: {
        default: "px-3 py-1 border border-border",
        underline: "border-0 border-b-2 border-transparent bg-transparent rounded-none px-0 pb-3",
      },
      state: {
        active: "",
        inactive: "",
      },
      disabled: {
        true: "opacity-50 cursor-not-allowed",
        false: "",
      },
    },
    compoundVariants: [
      { variant: "default", state: "active", class: "bg-foreground text-background font-bold border-foreground" },
      { variant: "default", state: "inactive", disabled: false, class: "bg-background text-foreground hover:bg-secondary focus-visible:bg-foreground focus-visible:text-background focus-visible:font-bold focus-visible:border-foreground" },
      { variant: "underline", state: "active", class: "border-b-foreground text-foreground font-bold focus-visible:ring-1 focus-visible:ring-foreground focus-visible:ring-offset-2 focus-visible:ring-offset-background" },
      { variant: "underline", state: "inactive", disabled: false, class: "text-muted-foreground hover:text-foreground hover:border-b-border focus-visible:text-foreground focus-visible:border-b-foreground focus-visible:ring-1 focus-visible:ring-foreground focus-visible:ring-offset-2 focus-visible:ring-offset-background" },
    ],
    defaultVariants: {
      variant: "default",
      state: "inactive",
      disabled: false,
    },
  }
);

export interface TabsTriggerProps extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, "value" | "disabled"> {
  value: string;
  disabled?: boolean;
  ref?: Ref<HTMLButtonElement>;
}

export function TabsTrigger({ value, children, className, disabled, ref, onClick, ...rest }: TabsTriggerProps) {
  const { tabsId, value: selectedValue, onChange, panelValues, variant, orientation } = useTabsContext();
  const isActive = selectedValue === value;
  const panelId = panelValues.includes(value) ? getTabPanelId(tabsId, value) : undefined;

  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
    if (disabled) {
      event.preventDefault();
      return;
    }

    onClick?.(event);
    if (!event.defaultPrevented) onChange(value);
  };

  return (
    <button
      {...rest}
      ref={ref}
      type="button"
      id={getTabTriggerId(tabsId, value)}
      role="tab"
      aria-selected={isActive}
      aria-controls={panelId}
      aria-disabled={disabled || undefined}
      disabled={disabled}
      tabIndex={isActive && !disabled ? 0 : -1}
      data-diffgazer-navigation-item="tab"
      data-value={value}
      data-state={isActive ? "active" : "inactive"}
      data-orientation={orientation}
      onClick={handleClick}
      className={cn(
        tabsTriggerVariants({ variant, state: isActive ? "active" : "inactive", disabled: !!disabled }),
        className
      )}
    >
      {children}
    </button>
  );
}

"use client";

import { type HTMLAttributes, type Ref } from "react";
import { cn } from "@/lib/utils";
import { getTabPanelId, getTabTriggerId, useTabsContext } from "./tabs-context";

export interface TabsContentProps extends HTMLAttributes<HTMLDivElement> {
  value: string;
  ref?: Ref<HTMLDivElement>;
}

export function TabsContent({ value, children, className, ref, ...rest }: TabsContentProps) {
  const { tabsId, value: selectedValue, orientation, triggerValues } = useTabsContext();
  const isActive = selectedValue === value;
  const triggerId = triggerValues.includes(value) ? getTabTriggerId(tabsId, value) : undefined;

  return (
    <div
      ref={ref}
      role="tabpanel"
      id={getTabPanelId(tabsId, value)}
      aria-labelledby={triggerId}
      data-state={isActive ? "active" : "inactive"}
      data-orientation={orientation}
      hidden={!isActive}
      tabIndex={isActive ? 0 : undefined}
      className={cn("mt-2 focus-visible:outline focus-visible:outline-2 focus-visible:outline-foreground focus-visible:outline-offset-2", className)}
      {...rest}
    >
      {children}
    </div>
  );
}

"use client";

import { createContext, useContext } from "react";

function encodeIdPart(value: string): string {
  return encodeURIComponent(value);
}

export function getTabTriggerId(tabsId: string, value: string): string {
  return `${tabsId}-tab-${encodeIdPart(value)}`;
}

export function getTabPanelId(tabsId: string, value: string): string {
  return `${tabsId}-tabpanel-${encodeIdPart(value)}`;
}

export interface TabsContextValue {
  tabsId: string;
  value: string;
  onChange: (value: string) => void;
  panelValues: string[];
  triggerValues: string[];
  orientation: "horizontal" | "vertical";
  variant: "default" | "underline";
  activationMode: "automatic" | "manual";
}

export const TabsContext = createContext<TabsContextValue | undefined>(undefined);

export function useTabsContext() {
  const context = useContext(TabsContext);
  if (!context) {
    throw new Error("Tabs compound components must be used within Tabs");
  }
  return context;
}
